import asyncio
import uuid
from collections import defaultdict

# Simulate a database with player and item information
players = {}
items = {}
player_items = {}

async def handle_connection(websocket, path):
    global players
    player_id = str(uuid.uuid4())
    players[player_id] = {
        'websocket': websocket,
        'inventory': []
    }

    while True:
        try:
            msg = await websocket.recv()
            print(f"Received message from {player_id}: {msg}")
            
            if msg.startswith('req_item'):
                player, item_id = msg.split(':')
                players[player]['inventory'].append(item_id)
                
            elif msg.startswith('send_item'):
                sender_player, recipient_player, item_id = msg.split(':')
                if item_id in players[sender_player]['inventory']:
                    players[recipient_player].get('inventory').append(item_id)
                    players[sender_player]['inventory'].remove(item_id)
                    
        except websockets.ConnectionClosed:
            print(f"Connection closed for {player_id}")
            del players[player_id]

async def main():
    # Create a new WebSocket server
    start_server = websockets.serve(handle_connection, "localhost", 8765)

    # Start the server
    asyncio.get_event_loop().run_until_complete(start_server)
    asyncio.get_event_loop().run_forever()

if __name__ == "__main__":
    loop = asyncio.get_event_loop()
    loop.run_until_complete(main())